    for pid in cohort['known_member_party_ids']:
        assert pid in party_ids
    assert cohort['unknown_member_count'] == cohort['exact_count'] - len(cohort['known_member_party_ids'])
obs_by_id = {o['observation_id']: o for o in data['observations']}
for obs in data['observations']:
    if obs['obs_type'] "'!= '"'proposal' or obs['requested_by_observation_id'] is None:
        continue
    req = obs_by_id[obs['requested_by_observation_id']]
    assert req['obs_type'] == 'solicitation'
